class BaseTask:
    def __init__(self, title, points):
        self.title = title
        self.points = points if points >= 0 else 0
        self.done = False

    def mark_done(self):
        self.done = True

    def summary_line(self):
        status = 'done' if self.done else 'open'
        return f"{self.title} [{status}] - {self.points} pts"


class BugTask(BaseTask):
    def __init__(self, title, points, severity):
        super().__init__(title, points)
        self.severity = severity

    def summary_line(self):
        status = 'done' if self.done else 'open'
        return f"BUG {self.severity}: {self.title} [{status}] - {self.points} pts"


class FeatureTask(BaseTask):
    def __init__(self, title, points, area):
        super().__init__(title, points)
        self.area = area

    def summary_line(self):
        status = 'done' if self.done else 'open'
        return f"FEATURE {self.area}: {self.title} [{status}] - {self.points} pts"

print(BugTask('Fix login', 5, 'high').summary_line())
print(FeatureTask('Add export', 8, 'reports').summary_line())

